class RetrievalEvaluator:
    def __init__(self, corpus, eval_set):
        self.corpus = corpus
        self.eval_set = eval_set

    def evaluate(self, ranking_fn, k=5):
        mrr_total, pk_total, ndcg_total = 0.0, 0.0, 0.0
        n = len(self.eval_set)

        for item in self.eval_set:
            ranked = ranking_fn(item["query"], self.corpus)
            rel_set = set(item["relevant_ids"])
            rel_map = {did: 1 for did in item["relevant_ids"]}

            mrr_total += mean_reciprocal_rank(ranked, rel_set)
            pk_total += precision_at_k(ranked, rel_set, k)
            ndcg_total += ndcg_at_k(ranked, rel_map, k)

        return {
            "MRR": round(mrr_total / n, 4),
            f"P@{k}": round(pk_total / n, 4),
            f"NDCG@{k}": round(ndcg_total / n, 4),
        }

